import{_ as o,o as t,c as i,ai as a}from"./chunks/framework.B3x_xFnx.js";const u=JSON.parse('{"title":"Rooting and SafetyNet","description":"","frontmatter":{},"headers":[],"relativePath":"guides/HowToRoot.md","filePath":"guides/HowToRoot.md"}'),l={name:"guides/HowToRoot.md"};function n(s,e,d,r,c,p){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="rooting-and-safetynet" tabindex="-1">Rooting and SafetyNet <a class="header-anchor" href="#rooting-and-safetynet" aria-label="Permalink to “Rooting and SafetyNet”">​</a></h1><h2 id="rooting" tabindex="-1">Rooting <a class="header-anchor" href="#rooting" aria-label="Permalink to “Rooting”">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>Instructions are written assuming you have a device with an unlocked bootloader running PixelOS with PixelOS Recovery installed.</p><p>Commands can be run on Windows CMD, PowerShell, Bash, MacOS Terminal.</p><p>Make sure to enable USB Debugging from Developer Opions.</p><p>You may use the volume keys to navigate PixelOS Recovery if touch does not work</p></div><h3 id="from-pc-linux-mac" tabindex="-1">From PC/Linux/Mac <a class="header-anchor" href="#from-pc-linux-mac" aria-label="Permalink to “From PC/Linux/Mac”">​</a></h3><ol><li><p>Setup ADB and Fastboot. <a href="https://wiki.lineageos.org/adb_fastboot_guide#installing-adb-and-fastboot" target="_blank" rel="noreferrer">LineageOS Wiki</a></p></li><li><p>Download the <a href="https://github.com/topjohnwu/Magisk/releases/latest" target="_blank" rel="noreferrer">Latest Magisk Installer (APK File)</a> and save it to your ADB folder</p></li><li><p>Rename the file from <code>Magisk-vxx.x.apk</code> to <code>Magisk-vxx.x.zip</code></p></li><li><p>Connect your device to your computer using a charging/data transfer cable and connect to it with adb</p></li><li><p>Reboot the device to recovery by using the command <code>adb reboot recovery</code></p></li><li><p>You should be greeted by PixelOS Recovery screen</p></li><li><p>Select <code>Apply Update</code></p></li><li><p>Select <code>Apply from ADB</code></p></li><li><p>Sideload the Magisk installer using the command <code>adb sideload path/to/magisk/Magisk-vxx.x.zip</code><img src="https://github.com/PixelOS-Devices/stuff/raw/main/RootGuide/9.png" alt="ADB Sideload"></p></li><li><p>If your device now says <code>Signature verification failed. Install anyway?</code>, ignore the warning and click on <code>Yes</code></p></li><li><p>The installation should begin. When it is done, you should see it in the terminal window and on the display of the device <img src="https://github.com/PixelOS-Devices/stuff/raw/main/RootGuide/11.png" alt="ADB Sideload"></p></li><li><p>Unplug the device and reboot to system, by going back to main menu and selecting <code>Reboot system now</code></p></li><li><p>Once PixelOS boots up, open the newly created Magisk App and follow on-screen-instructions</p></li><li><p>Your device should now be rooted</p></li></ol><h3 id="from-sd-card" tabindex="-1">From SD Card <a class="header-anchor" href="#from-sd-card" aria-label="Permalink to “From SD Card”">​</a></h3><ol><li>Download the <a href="https://github.com/topjohnwu/Magisk/releases/latest" target="_blank" rel="noreferrer">Latest Magisk Installer (APK File)</a> to your SD Card</li><li>Rename the file from <code>Magisk-vxx.x.apk</code> to <code>Magisk-vxx.x.zip</code></li><li>Reboot the device to recovery by holding Volume Up + Power Button <code>[Might change from device to device]</code></li><li>You should be greeted by PixelOS Recovery screen</li><li>Select <code>Apply Update</code></li><li>Select <code>Choose from sdcard1</code></li><li>Select the file you downloaded, ie <code>Magisk-vxx.x.zip</code></li><li>If your device now says <code>Signature verification failed. Install anyway?</code>, ignore the warning and click on <code>Yes</code></li><li>The installation should begin. When it is done, you should see it on the display of the device</li><li>Reboot to system, by going back to main menu and selecting <code>Reboot system now</code></li><li>Once PixelOS boots up, open the newly created Magisk App and follow on-screen-instructions</li><li>Your device should now be rooted</li></ol><h2 id="safetynet" tabindex="-1">SafetyNet <a class="header-anchor" href="#safetynet" aria-label="Permalink to “SafetyNet”">​</a></h2><p>SafetyNet on all PixelOS builds should pass by default without the need to do anything further. However, if you have rooted you device, follow the steps below to pass SafetyNet</p><ol><li><p>Download <a href="https://github.com/kdrag0n/safetynet-fix/releases/latest" target="_blank" rel="noreferrer">kdrag0n&#39;s Universal SafetyNet Fix</a> to your device</p></li><li><p>Open Magisk App</p></li><li><p>Select the gear icon on the top right <img src="https://github.com/PixelOS-Devices/stuff/raw/main/RootGuide/magiskApp.png" alt="Magisk App"></p></li><li><p>Scroll down to <code>Magisk</code></p></li><li><p>Enable <code>Zygisk</code> and <code>Enforce DenyList</code></p></li><li><p>You can ignore the toast saying <code>Reboot to apply changes</code><img src="https://github.com/PixelOS-Devices/stuff/raw/main/RootGuide/ZygiskDenyList.png" alt="Zygisk DenyList"></p></li><li><p>Go back, and select Modules <img src="https://github.com/PixelOS-Devices/stuff/raw/main/RootGuide/MagiskModules.png" alt="Modules"></p></li><li><p>Select the downloaded file</p></li><li><p>It should start installing <img src="https://github.com/PixelOS-Devices/stuff/raw/main/RootGuide/SafetyNetFixInstall.png" alt="SafetyNet Fix Installed"></p></li><li><p>Press the blue <code>reboot</code> button on the right corner</p></li><li><p>Once the device reboots you should pass SafetyNet.</p></li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Some apps may still detect root, try adding them to DenyList.</p><p>Some apps may still break due to root, unfortunately there is nothing we can do to fix them. 😦</p></div>',11)])])}const g=o(l,[["render",n]]);export{u as __pageData,g as default};
